// In-memory pub/sub hub for the collaborative notepad.
// This module is server-only: it must never be bundled into client code.
// All state lives on `globalThis` so HMR module reloads in dev preserve it
// across requests that share the same Node.js process.

export type ClientId = string;

export interface Subscriber {
  /** Encode and write a chunk of text to the underlying response stream. */
  write: (chunk: string) => Promise<void>;
  /** Close the underlying response stream. Safe to call multiple times. */
  close: () => Promise<void>;
}

interface NotepadState {
  text: string;
  subscribers: Set<Subscriber>;
}

// Store the singleton state on `globalThis` so Vite's HMR re-evaluations
// of this module don't reset the document text or drop active subscribers.
const g = globalThis as unknown as { __qwikNotepadHub?: NotepadState };

function getState(): NotepadState {
  if (!g.__qwikNotepadHub) {
    g.__qwikNotepadHub = {
      text: "",
      subscribers: new Set<Subscriber>(),
    };
  }
  return g.__qwikNotepadHub;
}

export function getText(): string {
  return getState().text;
}

export async function broadcastUpdate(
  text: string,
  clientId: ClientId,
): Promise<void> {
  const state = getState();
  state.text = text;

  // SSE wire format: "event: update\ndata: {json}\n\n"
  // JSON.stringify always produces a single-line output, satisfying the
  // "single-line JSON object" requirement on the `data:` line.
  const message =
    "event: update\n" +
    "data: " +
    JSON.stringify({ text, clientId }) +
    "\n\n";

  // Snapshot to a plain array so we can safely iterate while subscribers
  // may concurrently unsubscribe during writes.
  const snapshot = Array.from(state.subscribers);
  for (const sub of snapshot) {
    try {
      await sub.write(message);
    } catch {
      // Swallow individual write failures; the abort handler is responsible
      // for cleaning up dead subscribers.
    }
  }
}

export function subscribe(subscriber: Subscriber): () => void {
  const state = getState();
  state.subscribers.add(subscriber);
  return () => {
    state.subscribers.delete(subscriber);
  };
}

import type { RequestHandler } from "@builder.io/qwik-city";
import {
  broadcastUpdate,
  getText,
  subscribe,
  type Subscriber,
} from "~/lib/notepad-hub";

// GET /api/notepad — opens a long-lived Server-Sent Events stream.
// On connect it emits a single `snapshot` event with the current document
// text, then forwards every subsequent edit as an `update` event.
export const onGet: RequestHandler = async (requestEvent) => {
  const encoder = new TextEncoder();

  // SSE requires these response headers. `X-Accel-Buffering: no` disables
  // any reverse-proxy buffering that would otherwise hold events back.
  requestEvent.headers.set("Content-Type", "text/event-stream");
  requestEvent.headers.set("Cache-Control", "no-cache, no-transform");
  requestEvent.headers.set("Connection", "keep-alive");
  requestEvent.headers.set("X-Accel-Buffering", "no");
  requestEvent.status(200);

  const writableStream = requestEvent.getWritableStream();
  const writer = writableStream.getWriter();

  let closed = false;
  const writeSafely = async (chunk: string): Promise<void> => {
    if (closed) return;
    await writer.write(encoder.encode(chunk));
  };
  const closeSafely = async (): Promise<void> => {
    if (closed) return;
    closed = true;
    try {
      await writer.close();
    } catch {
      // Stream may already be closed by the runtime; that's fine.
    }
  };

  const subscriber: Subscriber = {
    write: writeSafely,
    close: closeSafely,
  };

  const unsubscribe = subscribe(subscriber);

  // Cleanup on disconnect: the runtime fires `signal` (`requestEvent.signal`
  // and `requestEvent.request.signal` are the same) when the client goes
  // away, including when the response stream errors out.
  const cleanup = () => {
    unsubscribe();
    void closeSafely();
  };
  requestEvent.signal.addEventListener("abort", cleanup);

  // Send the initial snapshot before anything else so connecting clients
  // always receive the latest stored text as the very first message.
  const snapshotMessage =
    "event: snapshot\n" +
    "data: " +
    JSON.stringify({ text: getText() }) +
    "\n\n";
  try {
    await writer.write(encoder.encode(snapshotMessage));
  } catch {
    cleanup();
    return;
  }
};

// POST /api/notepad — accepts an edit, updates the stored document text,
// broadcasts it to all connected SSE clients, and acknowledges with JSON.
export const onPost: RequestHandler = async (requestEvent) => {
  const body = (await requestEvent.parseBody()) as
    | { text?: unknown; clientId?: unknown }
    | null
    | undefined;

  const text = typeof body?.text === "string" ? body.text : "";
  const clientId = typeof body?.clientId === "string" ? body.clientId : "";

  await broadcastUpdate(text, clientId);

  requestEvent.json(200, { ok: true });
};

import {
  $,
  component$,
  useSignal,
  useVisibleTask$,
} from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";

export default component$(() => {
  // Reactive state holding the current document text shown in the textarea.
  const text = useSignal("");

  // Unique id assigned to this tab on first mount; used to ignore echoes of
  // our own broadcasts so they don't clobber the text the user is typing.
  const clientId = useSignal("");

  useVisibleTask$(({ cleanup }) => {
    // Generate a per-tab id. crypto.randomUUID is available in all modern
    // browsers; fall back to a Math.random-based id just in case.
    const id =
      typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
        ? crypto.randomUUID()
        : `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
    clientId.value = id;

    const es = new EventSource("/api/notepad");

    es.addEventListener("snapshot", (event) => {
      try {
        const data = JSON.parse((event as MessageEvent).data) as {
          text?: string;
        };
        if (typeof data.text === "string") {
          text.value = data.text;
        }
      } catch {
        // Ignore malformed payloads.
      }
    });

    es.addEventListener("update", (event) => {
      try {
        const data = JSON.parse((event as MessageEvent).data) as {
          text?: string;
          clientId?: string;
        };
        // Ignore echoes of our own edits so they don't clobber the text
        // the user is currently typing.
        if (data.clientId && data.clientId === clientId.value) return;
        if (typeof data.text === "string") {
          text.value = data.text;
        }
      } catch {
        // Ignore malformed payloads.
      }
    });

    cleanup(() => {
      es.close();
    });
  });

  const handleInput = $(async (_event: Event, el: HTMLTextAreaElement) => {
    const value = el.value;
    // Update local state immediately so the textarea reflects the keystroke
    // without waiting for the server round-trip.
    text.value = value;

    // Don't try to POST if we haven't received our client id yet.
    if (!clientId.value) return;

    try {
      await fetch("/api/notepad", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: value, clientId: clientId.value }),
      });
    } catch {
      // Network errors are ignored for the demo; the next keystroke will
      // resync via a new POST.
    }
  });

  return (
    <>
      <h1>Collaborative Notepad</h1>
      <p>
        Open this page in multiple tabs to see live updates. Edits you make
        show up in every other tab in real time.
      </p>
      <textarea
        value={text.value}
        onInput$={handleInput}
        rows={20}
        cols={80}
        placeholder="Start typing..."
        style={{
          width: "100%",
          minHeight: "50vh",
          fontFamily: "monospace",
          fontSize: "14px",
          padding: "8px",
          boxSizing: "border-box",
        }}
      />
    </>
  );
});

